 1	import * as React from 'react';
 2	import { NotificationMessage, MessageType } from '../../types/MessageCenter';
 3	import { Alert, AlertActionCloseButton, AlertGroup, AlertVariant } from '@patternfly/react-core';
 4	
 5	type NotificationListProps = {
 6	  messages: NotificationMessage[];
 7	  onDismiss: (message: NotificationMessage, userDismissed: boolean) => void;
 8	};
 9	
10	export const NotificationList: React.FC<NotificationListProps> = (props: NotificationListProps) => {
11	  return (
12	    <AlertGroup isToast isLiveRegion>
13	      {props.messages.map(message => {
14	        let variant: AlertVariant;
15	
16	        switch (message.type) {
17	          case MessageType.SUCCESS:
18	            variant = AlertVariant.success;
19	            break;
20	          case MessageType.WARNING:
21	            variant = AlertVariant.warning;
22	            break;
23	          case MessageType.INFO:
24	            variant = AlertVariant.info;
25	            break;
26	          default:
27	            variant = AlertVariant.danger;
28	        }
29	
30	        return (
31	          <Alert
32	            key={`toast_${message.id}`}
33	            variant={variant}
34	            title={message.content}
35	            timeout={true}
36	            actionClose={<AlertActionCloseButton onClose={() => props.onDismiss(message, true)} />}
37	          />
38	        );
39	      })}
40	    </AlertGroup>
41	  );
42	};

